output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?year WHERE {
  wd:Q2331 wdt:P39 wd:Q4191 ; wdt:P585 ?year .
}

args.sparql:
SELECT ?property (SAMPLE(?objectLabel) AS ?object)
WHERE {
  wd:Q2331 ?property wd:Q334.
  OPTIONAL { wd:Q334 rdfs:label ?objectLabel. }
}
LIMIT 20
